insert into public.theories (title, summary, category_slug, status, score, is_seed, submitted_by) values
  ('Mondlandung gefälscht', 'Apollo 11 (1969) sei in einem Filmstudio inszeniert worden, angeblich unter Regie von Stanley Kubrick.', 'astronomy-space', 'accepted', 5, true, '254b9fb9-638e-4ade-8769-f6ecfac80398'),
